codeExercises.solution:
const mongoose = require('mongoose');

const boardSchema = new mongoose.Schema({
  title: { type: String, required: true },
  columnOrderIds: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Column' }]
});

boardSchema.statics.pushColumnOrderIds = async function(column) {
  try {
    const result = await this.findOneAndUpdate(
      { _id: column.boardId },
      { $push: { columnOrderIds: column._id } },
      { new: true } // hoặc { returnDocument: 'after' }
    );
    return result;
  } catch (error) { throw error; }
};

module.exports = mongoose.model('Board', boardSchema);

