const mongoose = require('mongoose');

const columnSchema = new mongoose.Schema({
  boardId: { type: mongoose.Schema.Types.ObjectId, required: true, ref: 'Board' },
  title: { type: String, required: true },
  cardOrderIds: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Card' }]
});

columnSchema.statics.pushCardOrderIds = async function(card) {
  try {
    const result = await this.findOneAndUpdate(
      { _id: card.columnId },
      { $push: { cardOrderIds: card._id } },
      { new: true }
    );
    return result;
  } catch (error) { throw error; }
};

module.exports = mongoose.model('Column', columnSchema);

